/*! 
 * @brief Flags for port timesync configuration. 
 */ 
#define PORTMOD_PORT_TIMESYNC_CONFIG_ENABLE 0x1 /**< enable/disable the timesync. */
#define PORTMOD_PORT_TIMESYNC_CONFIG_SFD 0x2 /**<  select as SFD timestamp location. Otherwise check MAC_DA. */
#define PORTMOD_PORT_TIMESYNC_CONFIG_COMP_MODE_ON 0x4 /**<  Lane Compensation ON. */
#define PORTMOD_PORT_TIMESYNC_CONFIG_COMP_MODE_LATEST_LANE 0x8 /**< AM comp mode. LATEST or EARLIEST Lane */
#define PORTMOD_PORT_TIMESYNC_CONFIG_MAC_DA 0x10 /**<  valid when SFD is off. Select MAC_DA as timestamp location. Otherwise SOP. */

#define PORTMOD_PORT_TIMESYNC_CONFIG_ENABLE_SET(flags) ((flags) |= PORTMOD_PORT_TIMESYNC_CONFIG_ENABLE)
#define PORTMOD_PORT_TIMESYNC_CONFIG_SFD_SET(flags) ((flags) |= PORTMOD_PORT_TIMESYNC_CONFIG_SFD)
#define PORTMOD_PORT_TIMESYNC_CONFIG_COMP_MODE_ON_SET(flags) ((flags) |= PORTMOD_PORT_TIMESYNC_CONFIG_COMP_MODE_ON)
#define PORTMOD_PORT_TIMESYNC_CONFIG_COMP_MODE_LATEST_LANE_SET(flags) ((flags) |= PORTMOD_PORT_TIMESYNC_CONFIG_COMP_MODE_LATEST_LANE)
#define PORTMOD_PORT_TIMESYNC_CONFIG_MAC_DA_SET(flags) ((flags) |= PORTMOD_PORT_TIMESYNC_CONFIG_MAC_DA)

#define PORTMOD_PORT_TIMESYNC_CONFIG_ENABLE_CLR(flags) ((flags) &= ~PORTMOD_PORT_TIMESYNC_CONFIG_ENABLE)
#define PORTMOD_PORT_TIMESYNC_CONFIG_SFD_CLR(flags) ((flags) &= ~PORTMOD_PORT_TIMESYNC_CONFIG_SFD)
#define PORTMOD_PORT_TIMESYNC_CONFIG_COMP_MODE_ON_CLR(flags) ((flags) &= ~PORTMOD_PORT_TIMESYNC_CONFIG_COMP_MODE_ON)
#define PORTMOD_PORT_TIMESYNC_CONFIG_COMP_MODE_LATEST_LANE_CLR(flags) ((flags) &= ~PORTMOD_PORT_TIMESYNC_CONFIG_COMP_MODE_LATEST_LANE)
#define PORTMOD_PORT_TIMESYNC_CONFIG_MAC_DA_CLR(flags) ((flags) &= ~PORTMOD_PORT_TIMESYNC_CONFIG_MAC_DA)

